const input = $input.first().json;
const bodyData = input.body || {};
const { id, nombre, tipo, nivel, categoria, dia_1, dia_2, hora_inicio, hora_fin, cupo_max, precio_mensual, descripcion } = bodyData;

if (!id) {
  throw new Error('ID del horario es requerido');
}

let updateFields = ["updated_at = NOW()"];

if (nombre) updateFields.unshift(`nombre = '${nombre.replace(/'/g, "''")}'`);
if (tipo) updateFields.unshift(`tipo = '${tipo}'`);
if (nivel) updateFields.unshift(`nivel = '${nivel}'`);
if (categoria) updateFields.unshift(`categoria = '${categoria}'`);
if (dia_1) updateFields.unshift(`dia_1 = '${dia_1}'`);
if (dia_2) updateFields.unshift(`dia_2 = '${dia_2}'`);
if (hora_inicio) updateFields.unshift(`hora_inicio = '${hora_inicio}'::time`);
if (hora_fin) updateFields.unshift(`hora_fin = '${hora_fin}'::time`);
if (cupo_max) updateFields.unshift(`cupo_max = ${parseInt(cupo_max)}`);
if (precio_mensual) updateFields.unshift(`precio_mensual = ${parseFloat(precio_mensual)}`);
if (descripcion) updateFields.unshift(`descripcion = '${descripcion.replace(/'/g, "''")}'`);

const query = `UPDATE horarios
SET ${updateFields.join(', ')}
WHERE id = ${parseInt(id)}
RETURNING id, nombre, tipo, nivel, categoria, dia_1, dia_2, hora_inicio, hora_fin, cupo_max, activo;`;

return [{
  json: {
    query
  }
}];

const horario = $('arma query').first().json;

return [{
  json: {
    success: true,
    mensaje: 'Horario actualizado',
    horario
  }
}];

